1. Sort conversations by `updated_at` DESC on initial load
2. Re-sort when real-time updates arrive
3. Handle Hebrew date sorting correctly
4. Ensure UI updates properly

Here's the plan:

```typescript
// src/components/tenant/ChatTab.tsx

'use client';

import { useState, useEffect, useRef } from 'react';
import { createClientComponentClient } from '@supabase/auth-helpers-nextjs';
import styles from './ChatTab.module.css';

interface Conversation {
  id: string;
  phone_number: string;
  contact_name: string | null;
  is_group: boolean;
  updated_at: string;
  last_message?: string;
  unread_count?: number;
}

export default function ChatTab({ tenantId }: { tenantId: string }) {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const supabase = createClientComponentClient();
  const subscriptionRef = useRef<any>(null);
  const isMountedRef = useRef(true);

  // Sorting function for conversations
  const sortConversations = (convs: Conversation[]): Conversation[] => {
    return [...convs].sort((a, b) => {
      // Convert dates to timestamps for comparison
      const dateA = new Date(a.updated_at).getTime();
      const dateB = new Date(b.updated_at).getTime();
      // Sort DESC (newest first)
      return dateB - dateA;
    });
  };

  // Fetch initial conversations
  useEffect(() => {
    const fetchConversations = async () => {
      try {
        setLoading(true);
        const { data, error } = await supabase
          .from('conversations')
          .select('*')
          .eq('tenant_id', tenantId)
          .order('updated_at', { ascending: false }); // Already sorted from DB

        if (error) throw error;

        if (isMountedRef.current) {
          // Apply additional client-side sorting for safety
          const sortedData = sortConversations(data || []);
          setConversations(sortedData);
          setError(null);
        }
      } catch (err) {
        console.error('Error fetching conversations:', err);
        if (isMountedRef.current) {
          setError('Failed to load conversations');
        }
      } finally {
        if (isMountedRef.current) {
          setLoading(false);
        }
      }
    };

    fetchConversations();

    // Cleanup
    return () => {
      isMountedRef.current = false;
    };
  }, [tenantId, supabase]);

  // Set up real-time subscription
  useEffect(() => {
    // Clean up existing subscription
    if (subscriptionRef.current) {
      subscriptionRef.current.unsubscribe();
    }

    // Create new subscription
    subscriptionRef.current = supabase
      .channel(`conversations:tenant=${tenantId}`)
      .on(
        'postgres_changes',
        {
          event: '*', // Listen to all events (INSERT, UPDATE, DELETE)
          schema: 'public',
          table: 'conversations',
          filter: `tenant_id=eq.${tenantId}`,
        },
        (payload) => {
          console.log('Real-time update received:', payload);

          setConversations((currentConvs) => {
            let updatedConvs = [...currentConvs];

            switch (payload.eventType) {
              case 'INSERT':
                // Add new conversation
                updatedConvs.push(payload.new as Conversation);
                break;

              case 'UPDATE':
                // Update existing conversation
                const updateIndex = updatedConvs.findIndex(
                  (conv) => conv.id === payload.new.id
                );
                if (updateIndex !== -1) {
                  updatedConvs[updateIndex] = payload.new as Conversation;
                } else {
                  // If not found, add it (might be a new conversation from another session)
                  updatedConvs.push(payload.new as Conversation);
                }
                break;

              case 'DELETE':
                // Remove deleted conversation
                updatedConvs = updatedConvs.filter(
                  (conv) => conv.id !== payload.old.id
                );
                break;
            }

            // Re-sort after update
            return sortConversations(updatedConvs);
          });
        }
      )
      .subscribe();

    // Cleanup on unmount or tenantId change
    return () => {
      if (subscriptionRef.current) {
        subscriptionRef.current.unsubscribe();
        subscriptionRef.current = null;
      }
    };
  }, [tenantId, supabase]);

  // Format date for display (handles Hebrew dates)
  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

    if (diffDays === 0) {
      // Today - show time
      return date.toLocaleTimeString('he-IL', { 
        hour: '2-digit', 
        minute: '2-digit' 
      });
    } else if (diffDays === 1) {
      return 'אתמול';
    } else if (diffDays < 7) {
      // This week - show day name
      return date.toLocaleDateString('he-IL', { weekday: 'short' });
    } else {
      // Older - show date
      return date.toLocaleDateString('he-IL', { 
        day: '2-digit', 
        month: '2-digit' 
      });
    }
  };

  if (loading) {
    return <div className={styles.loading}>טוען שיחות...</div>;
  }

  if (error) {
    return <div className={styles.error}>{error}</div>;
  }

  if (conversations.length === 0) {
    return (
      <div className={styles.empty}>
        <p>אין שיחות עדיין</p>
        <p>הסוכן יתחיל לענות ללקוחות ברגע שיתחברו</p>
      </div>
    );
  }

  return (
    <div className={styles.container}>
      <div className={styles.header}>
        <h2>שיחות</h2>
        <span className={styles.count}>{conversations.length} שיחות</span>
      </div>

      <div className={styles.conversationList}>
        {conversations.map((conversation) => (
          <div
            key={conversation.id}
            className={styles.conversationItem}
            onClick={() => {
              // Handle conversation selection
              console.log('Selected conversation:', conversation.id);
            }}
          >
            <div className={styles.avatar}>
              {conversation.is_group ? '👥' : '👤'}
            </div>

            <div className={styles.conversationInfo}>
              <div className={styles.conversationHeader}>
                <span className={styles.contactName}>
                  {conversation.contact_name || conversation.phone_number}
                </span>
                <span className={styles.timestamp}>
                  {formatDate(conversation.updated_at)}
                </span>
              </div>

              <div className={styles.conversationPreview}>
                <span className={styles.lastMessage}>
                  {conversation.last_message || 'אין הודעות עדיין'}
                </span>
                {conversation.unread_count && conversation.unread_count > 0 && (
                  <span className={styles.unreadBadge}>
                    {conversation.unread_count}
                  </span>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
```

